<?php
 declare(strict_types=1); namespace tapmeppe\composer\database\seeders; use App\DataMapper\CompanySettings; use App\Models\Account; use App\Models\Client; use App\Models\ClientContact; use App\Models\Company; use App\Models\CompanyUser; use App\Models\User; use Illuminate\Database\Eloquent\Model; use Illuminate\Support\Facades\Hash; use Illuminate\Support\Str; class AccountingAdministrator extends \tapmeppe\composer\helpers\Seeder { public function runInner(array $parameters): bool { if (CompanyUser::where('is_owner', 1)->where('is_admin', 1)->where('is_locked', 0)->count()) return false; Model::unguard(); $account = Account::factory()->create(); $settings = CompanySettings::defaults(); $settings->name = $parameters['company']; $settings->email = $parameters['email']; $settings->website = "https://{$parameters['domain']}"; $settings->currency_id = config('ninja.i18n.currency_id'); $settings->language_id = config('ninja.i18n.language_id'); $settings->country_id = config('ninja.i18n.country_id'); $settings->timezone_id = config('ninja.i18n.timezone_id'); $company = Company::factory()->create([ 'account_id' => $account->id, 'domain' => $parameters['domain'], 'settings' => $settings, 'first_day_of_week' => config('ninja.i18n.first_day_of_week'), 'first_month_of_year' => config('ninja.i18n.first_month_of_year'), ]); $account->default_company_id = $company->id; $account->save(); $user = User::factory()->create([ 'account_id' => $account->id, 'confirmation_code' => Str::random(config('ninja.key_length')), ]); $userPermissions = collect([ 'view_invoice', 'view_client', 'edit_client', 'edit_invoice', 'create_invoice', 'create_client', ]); $user->companies()->attach($company->id, [ 'account_id' => $account->id, 'is_owner' => 1, 'is_admin' => 1, 'notifications' => CompanySettings::notificationDefaults(), 'permissions' => $userPermissions->toJson(), 'settings' => null, 'is_locked' => 0, ]); $client = Client::factory()->create([ 'user_id' => $user->id, 'company_id' => $company->id, ]); ClientContact::create([ 'first_name' => $parameters['first_name'], 'last_name' => $parameters['last_name'], 'email' => $parameters['email'], 'company_id' => $company->id, 'password' => Hash::make($parameters['password']), 'email_verified_at' => now(), 'client_id' => $client->id, ]); return true; } } 